require_once dirname(__DIR__).'/helpers.php';require_admin();$id=(int)($_GET['id']??$_POST['id']??0);$row=['title'=>'','summary'=>'','description'=>'','category'=>'Kemanusiaan','beneficiary'=>'','location'=>'','target_amount'=>'','status'=>'active','deadline'=>date('Y-m-d',strtotime('+30 days')),'cover_image'=>null];if($id){$stmt=db()->prepare('SELECT * FROM campaigns WHERE id=?');$stmt->execute([$id]);$row=$stmt->fetch()?:$row;}$pageTitle=$id?'Edit Kampanye':'Kampanye Baru';$errors=[];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();foreach(['title','summary','description','category','beneficiary','location','status','deadline'] as $k)$row[$k]=trim($_POST[$k]??'');$row['target_amount']=(float)preg_replace('/[^0-9]/','',$_POST['target_amount']??'0');if($row['title']===''||$row['summary']===''||$row['description']==='')$errors[]='Judul, ringkasan, dan deskripsi wajib diisi.';if($row['target_amount']<=0)$errors[]='Target harus lebih dari nol.';try{$image=upload_file('cover_image','campaigns',['image/jpeg','image/png','image/webp']);if($image)$row['cover_image']=$image;}catch(Throwable $e){$errors[]=$e->getMessage();}if(!$errors){$slug=slugify($row['title']);if($id){$stmt=db()->prepare('UPDATE campaigns SET title=?,summary=?,description=?,category=?,beneficiary=?,location=?,target_amount=?,status=?,deadline=?,cover_image=? WHERE id=?');$stmt->execute([$row['title'],$row['summary'],$row['description'],$row['category'],$row['beneficiary'],$row['location'],$row['target_amount'],$row['status'],$row['deadline'],$row['cover_image'],$id]);}else{$base=$slug;$n=1;while(db()->query("SELECT COUNT(*) FROM campaigns WHERE slug=".db()->quote($slug))->fetchColumn())$slug=$base.'-'.$n++;$stmt=db()->prepare('INSERT INTO campaigns(title,slug,summary,description,category,beneficiary,location,target_amount,status,deadline,cover_image,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)');$stmt->execute([$row['title'],$slug,$row['summary'],$row['description'],$row['category'],$row['beneficiary'],$row['location'],$row['target_amount'],$row['status'],$row['deadline'],$row['cover_image'],user()['id']]);}flash('success','Kampanye berhasil disimpan.');redirect('admin/campaigns.php');}}
include dirname(__DIR__).'/partials/header.php';include __DIR__.'/nav.php';?>
<section class="admin-content container"><div class="admin-heading"><div><span class="eyebrow">Editor</span><h1><?=e($pageTitle)?></h1></div></div><div class="glass form-card admin-form"><?php if($errors):?><div class="alert error"><ul><?php foreach($errors as $er):?><li><?=e($er)?></li><?php endforeach;?></ul></div><?php endif;?><form method="post" enctype="multipart/form-data" class="form-grid"><?=csrf_field()?><input type="hidden" name="id" value="<?=$id?>"><label class="full">Judul<input name="title" value="<?=e((string)$row['title'])?>" required></label><label>Kategori<select name="category"><?php foreach(['Kemanusiaan','Kesehatan','Pendidikan','Lingkungan','Bencana'] as $c):?><option <?=$row['category']===$c?'selected':''?>><?=$c?></option><?php endforeach;?></select></label><label>Target dana<input name="target_amount" data-currency value="<?=e((string)$row['target_amount'])?>" required></label><label>Penerima manfaat<input name="beneficiary" value="<?=e((string)$row['beneficiary'])?>" required></label><label>Lokasi<input name="location" value="<?=e((string)$row['location'])?>" required></label><label>Tenggat waktu<input type="date" name="deadline" value="<?=e((string)$row['deadline'])?>"></label><label>Status<select name="status"><?php foreach(['draft','active','completed','closed'] as $s):?><option <?=$row['status']===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select></label><label class="full">Ringkasan<textarea name="summary" rows="2" required><?=e((string)$row['summary'])?></textarea></label><label class="full">Deskripsi lengkap<textarea name="description" rows="8" required><?=e((string)$row['description'])?></textarea></label><label class="full">Gambar sampul<input type="file" name="cover_image" accept="image/*"><small>Kosongkan untuk mempertahankan gambar lama.</small></label><button class="btn primary full">Simpan Kampanye</button></form></div></section>
